.sig-glassmorphism-hero {
  position: relative;
  width: min(100%, 980px);
  min-height: 440px;
  display: grid;
  grid-template-columns: minmax(0, 1.08fr) minmax(260px, 0.82fr);
  gap: 34px;
  align-items: stretch;
  padding: 42px;
  overflow: hidden;
  border: 1px solid rgba(255,255,255,0.32);
  border-radius: 20px;
  background: linear-gradient(145deg, rgba(255,255,255,0.18), rgba(255,255,255,0.14));
  color: #f8fbfa;
  box-shadow: 0 30px 78px rgba(8,19,25,0.26);
  font-family: Inter, ui-sans-serif, system-ui, sans-serif;
}
.sig-glassmorphism-hero::before { content: ""; position: absolute; inset: 0; background: radial-gradient(circle at 18% 20%, rgba(255,255,255,0.34), transparent 22%), radial-gradient(circle at 86% 80%, rgba(217,243,255,0.24), transparent 24%); background-size: auto; opacity: 0.78; pointer-events: none; }
.sig-glassmorphism-hero > * { position: relative; z-index: 1; }
.sig-glassmorphism-hero .copy { display: grid; align-content: center; gap: 18px; }
.sig-glassmorphism-hero .kicker { width: fit-content; border: 1px solid rgba(255,255,255,0.32); border-radius: 999px; padding: 6px 10px; color: #d9f3ff; background: rgba(255,255,255,0.14); font-size: 11px; font-weight: 800; text-transform: uppercase; letter-spacing: 0; }
.sig-glassmorphism-hero h1 { margin: 0; max-width: 620px; font-family: Inter, ui-sans-serif, system-ui, sans-serif; font-size: clamp(40px, 6.4vw, 70px); font-weight: 760; line-height: 0.98; letter-spacing: 0; }
.sig-glassmorphism-hero p { margin: 0; max-width: 560px; color: rgba(248,251,250,0.74); font-size: 15px; line-height: 1.78; }
.sig-glassmorphism-hero .actions { display: flex; flex-wrap: wrap; gap: 10px; padding-top: 6px; }
.sig-glassmorphism-hero button { height: 40px; padding: 0 16px; border-radius: calc(20px / 2 + 4px); border: 1px solid rgba(255,255,255,0.32); font: inherit; font-size: 13px; font-weight: 700; cursor: pointer; transition: transform 180ms cubic-bezier(0.16, 1, 0.3, 1), border-color 180ms; }
.sig-glassmorphism-hero .primary { background: #d9f3ff; color: #102027; border-color: #d9f3ff; }
.sig-glassmorphism-hero .secondary { background: transparent; color: #f8fbfa; }
.sig-glassmorphism-hero button:hover { transform: translateY(-1px); border-color: #d9f3ff; }
.sig-glassmorphism-hero .artifact { display: grid; align-content: space-between; gap: 18px; padding: 22px; border: 1px solid rgba(255,255,255,0.32); border-radius: calc(20px - 2px); background: rgba(255,255,255,0.14); backdrop-filter: blur(18px) saturate(140%); }
.sig-glassmorphism-hero .artifact h2 { margin: 0; font-size: 13px; color: #d9f3ff; text-transform: uppercase; letter-spacing: 0; }
.sig-glassmorphism-hero .metric-grid { display: grid; grid-template-columns: 1fr 1fr; gap: 12px; }
.sig-glassmorphism-hero .metric { padding: 14px; border: 1px solid rgba(255,255,255,0.32); border-radius: calc(20px - 4px); background: color-mix(in srgb, rgba(255,255,255,0.18) 76%, transparent); }
.sig-glassmorphism-hero .metric strong { display: block; font-size: 30px; line-height: 1; font-variant-numeric: tabular-nums; }
.sig-glassmorphism-hero .metric span { display: block; margin-top: 6px; color: rgba(248,251,250,0.74); font-size: 11px; }
.sig-glassmorphism-hero .rail { height: 9px; border-radius: 999px; background: linear-gradient(90deg, #d9f3ff, #f2c673); }
@media (max-width: 780px) { .sig-glassmorphism-hero { grid-template-columns: 1fr; padding: 28px; } }

.sig-glassmorphism-card { width: min(100%, 390px); padding: 22px; border: 1px solid rgba(255,255,255,0.32); border-radius: 20px; background: rgba(255,255,255,0.18); color: #f8fbfa; box-shadow: 0 30px 78px rgba(8,19,25,0.26); font-family: Inter, ui-sans-serif, system-ui, sans-serif; }
.sig-glassmorphism-card .top { display: flex; align-items: start; justify-content: space-between; gap: 16px; margin-bottom: 24px; }
.sig-glassmorphism-card .label { color: #d9f3ff; font-size: 12px; font-weight: 800; text-transform: uppercase; letter-spacing: 0; }
.sig-glassmorphism-card .pill { border: 1px solid rgba(255,255,255,0.32); border-radius: 999px; padding: 5px 9px; color: rgba(248,251,250,0.74); background: rgba(255,255,255,0.14); font-size: 11px; }
.sig-glassmorphism-card h3 { margin: 0 0 10px; font-family: Inter, ui-sans-serif, system-ui, sans-serif; font-size: 32px; line-height: 1; letter-spacing: 0; }
.sig-glassmorphism-card p { margin: 0; color: rgba(248,251,250,0.74); font-size: 13px; line-height: 1.7; }
.sig-glassmorphism-card .strip { display: grid; grid-template-columns: 1fr auto; gap: 12px; margin-top: 22px; padding-top: 16px; border-top: 1px solid rgba(255,255,255,0.32); }
.sig-glassmorphism-card .strip strong { font-variant-numeric: tabular-nums; color: #f8fbfa; }
.sig-glassmorphism-card .signal { width: 38px; height: 38px; display: grid; place-items: center; border-radius: calc(20px - 4px); background: #d9f3ff; color: #102027; font-weight: 900; }

.sig-glassmorphism-nav { width: min(100%, 900px); min-height: 74px; display: flex; align-items: center; justify-content: space-between; gap: 24px; padding: 14px 16px; border: 1px solid rgba(255,255,255,0.32); border-radius: 20px; background: rgba(255,255,255,0.18); color: #f8fbfa; box-shadow: 0 30px 78px rgba(8,19,25,0.26); font-family: Inter, ui-sans-serif, system-ui, sans-serif; }
.sig-glassmorphism-nav .brand { display: flex; align-items: center; gap: 10px; min-width: max-content; font-family: Inter, ui-sans-serif, system-ui, sans-serif; font-size: 15px; font-weight: 800; letter-spacing: 0; }
.sig-glassmorphism-nav .mark { width: 30px; height: 30px; border-radius: calc(20px - 4px); background: linear-gradient(135deg, #d9f3ff, #f2c673); box-shadow: inset 0 0 0 1px rgba(255,255,255,0.32); }
.sig-glassmorphism-nav .links { display: flex; align-items: center; gap: 4px; min-width: 0; overflow-x: auto; }
.sig-glassmorphism-nav a { height: 34px; display: inline-flex; align-items: center; padding: 0 12px; border-radius: calc(20px - 6px); color: rgba(248,251,250,0.74); text-decoration: none; font-size: 13px; transition: color 160ms, background 160ms; white-space: nowrap; }
.sig-glassmorphism-nav a:hover, .sig-glassmorphism-nav a.active { color: #f8fbfa; background: rgba(255,255,255,0.14); }
.sig-glassmorphism-nav button { height: 34px; padding: 0 13px; border-radius: calc(20px - 6px); border: 1px solid #d9f3ff; background: #d9f3ff; color: #102027; font: inherit; font-size: 13px; font-weight: 700; cursor: pointer; white-space: nowrap; }
@media (max-width: 720px) { .sig-glassmorphism-nav { align-items: stretch; flex-direction: column; } }

.sig-glassmorphism-form { width: min(100%, 440px); display: grid; gap: 15px; padding: 22px; border: 1px solid rgba(255,255,255,0.32); border-radius: 20px; background: rgba(255,255,255,0.18); color: #f8fbfa; box-shadow: 0 30px 78px rgba(8,19,25,0.26); font-family: Inter, ui-sans-serif, system-ui, sans-serif; }
.sig-glassmorphism-form label { display: grid; gap: 7px; font-size: 13px; font-weight: 800; color: #f8fbfa; }
.sig-glassmorphism-form small { color: rgba(248,251,250,0.74); font-size: 12px; line-height: 1.55; font-weight: 400; }
.sig-glassmorphism-form .row { display: flex; gap: 10px; }
.sig-glassmorphism-form input { min-width: 0; flex: 1; height: 42px; border-radius: calc(20px - 6px); border: 1px solid rgba(255,255,255,0.32); background: rgba(255,255,255,0.14); color: #f8fbfa; padding: 0 12px; font: inherit; outline: none; transition: border-color 160ms, box-shadow 160ms; }
.sig-glassmorphism-form input:focus { border-color: #d9f3ff; box-shadow: 0 0 0 3px color-mix(in srgb, #d9f3ff 18%, transparent); }
.sig-glassmorphism-form button { height: 42px; padding: 0 14px; border-radius: calc(20px - 6px); border: 1px solid #d9f3ff; background: #d9f3ff; color: #102027; font: inherit; font-size: 13px; font-weight: 800; cursor: pointer; }
@media (max-width: 520px) { .sig-glassmorphism-form .row { flex-direction: column; } }

.sig-glassmorphism-table { width: min(100%, 780px); overflow: hidden; border: 1px solid rgba(255,255,255,0.32); border-radius: 20px; background: rgba(255,255,255,0.18); color: #f8fbfa; box-shadow: 0 30px 78px rgba(8,19,25,0.26); font-family: Inter, ui-sans-serif, system-ui, sans-serif; }
.sig-glassmorphism-table table { width: 100%; border-collapse: collapse; font-size: 13px; }
.sig-glassmorphism-table th, .sig-glassmorphism-table td { padding: 12px 14px; text-align: left; border-bottom: 1px solid rgba(255,255,255,0.32); }
.sig-glassmorphism-table th { color: rgba(248,251,250,0.74); font-size: 11px; font-weight: 900; text-transform: uppercase; letter-spacing: 0; background: rgba(255,255,255,0.14); }
.sig-glassmorphism-table td { color: #f8fbfa; }
.sig-glassmorphism-table tr:last-child td { border-bottom: 0; }
.sig-glassmorphism-table tbody tr:hover td { background: rgba(255,255,255,0.14); }
.sig-glassmorphism-table .mono { font-variant-numeric: tabular-nums; }
.sig-glassmorphism-table .status { display: inline-flex; align-items: center; gap: 6px; color: #d9f3ff; font-weight: 800; }
.sig-glassmorphism-table .status::before { content: ""; width: 7px; height: 7px; border-radius: 50%; background: #d9f3ff; }

.bg-glass-depth {
  min-height: 100vh;
  background: #030712;
  position: relative;
  overflow: hidden;
}
.bg-glass-depth .orb {
  position: absolute;
  border-radius: 50%;
}
.bg-glass-depth .orb-1 {
  width: 60vw;
  height: 60vw;
  background: rgba(29, 78, 216, 0.18);
  filter: blur(150px);
  top: -20%;
  left: -15%;
}
.bg-glass-depth .orb-2 {
  width: 40vw;
  height: 40vw;
  background: rgba(124, 58, 237, 0.12);
  filter: blur(120px);
  bottom: -10%;
  right: -10%;
}
.bg-glass-depth .orb-3 {
  width: 25vw;
  height: 25vw;
  background: rgba(6, 182, 212, 0.08);
  filter: blur(60px);
  top: 40%;
  left: 50%;
}

.btn-frost-pro {
  padding: 11px 22px;
  background: rgba(255,255,255,0.03);
  backdrop-filter: blur(16px) saturate(180%);
  -webkit-backdrop-filter: blur(16px) saturate(180%);
  color: rgba(255,255,255,0.9);
  font-family: 'Inter', -apple-system, sans-serif;
  font-size: 13px;
  font-weight: 500;
  border: 0.5px solid rgba(255,255,255,0.1);
  border-top-color: rgba(255,255,255,0.2);
  border-radius: 10px;
  cursor: pointer;
  transition: all 0.2s;
  box-shadow: 0 2px 8px rgba(0,0,0,0.15), 0 0 0 0.5px rgba(0,0,0,0.05);
}
.btn-frost-pro:hover {
  background: rgba(255,255,255,0.07);
  border-top-color: rgba(255,255,255,0.35);
  box-shadow: 0 4px 16px rgba(0,0,0,0.2), 0 0 0 0.5px rgba(0,0,0,0.08);
}
.btn-frost-pro:active {
  background: rgba(255,255,255,0.02);
  transform: scale(0.97);
  box-shadow: 0 1px 4px rgba(0,0,0,0.2);
}

.card-vision {
  width: 380px;
  padding: 32px;
  border-radius: 20px;
  background: rgba(255, 255, 255, 0.02);
  backdrop-filter: blur(40px) saturate(150%);
  -webkit-backdrop-filter: blur(40px) saturate(150%);
  border: 0.5px solid rgba(255, 255, 255, 0.06);
  border-top-color: rgba(255, 255, 255, 0.15);
  box-shadow:
    0 8px 32px rgba(0, 0, 0, 0.25),
    0 2px 8px rgba(0, 0, 0, 0.1),
    inset 0 -1px 1px rgba(0, 0, 0, 0.05);
  color: rgba(255, 255, 255, 0.92);
}

.hero-glass-orb {
  min-height: 100vh;
  display: flex;
  align-items: center;
  justify-content: center;
  background: #030712;
  position: relative;
  overflow: hidden;
}
.hero-glass-orb .orb {
  position: absolute;
  width: 600px;
  height: 600px;
  border-radius: 50%;
  background: radial-gradient(circle at 40% 40%, rgba(99,102,241,0.2) 0%, rgba(139,92,246,0.1) 40%, transparent 70%);
  filter: blur(80px);
  top: 50%;
  left: 50%;
  transform: translate(-50%, -50%);
}
.hero-glass-orb .panel {
  position: relative;
  padding: 48px 40px;
  border-radius: 24px;
  background: rgba(255,255,255,0.02);
  backdrop-filter: blur(40px) saturate(150%);
  border: 0.5px solid rgba(255,255,255,0.08);
  border-top-color: rgba(255,255,255,0.15);
  text-align: center;
  color: #e4e4e7;
  max-width: 480px;
  box-shadow: 0 16px 64px rgba(0,0,0,0.3);
}
.hero-glass-orb .panel h1 {
  font-family: 'Inter', system-ui;
  font-size: 36px;
  font-weight: 700;
  margin: 0 0 12px;
  letter-spacing: -0.02em;
}
.hero-glass-orb .panel p {
  font-size: 15px;
  color: #a1a1aa;
  margin: 0;
  line-height: 1.6;
}

.nav-floating-pill {
  position: fixed;
  top: 16px;
  left: 50%;
  transform: translateX(-50%);
  display: inline-flex;
  gap: 2px;
  padding: 4px;
  border-radius: 50px;
  background: rgba(255,255,255,0.03);
  backdrop-filter: blur(20px) saturate(150%);
  border: 0.5px solid rgba(255,255,255,0.08);
  z-index: 1000;
}
.nav-floating-pill a {
  padding: 8px 16px;
  border-radius: 50px;
  font-family: 'Inter', system-ui;
  font-size: 13px;
  font-weight: 500;
  color: rgba(255,255,255,0.5);
  text-decoration: none;
  transition: all 0.2s;
}
.nav-floating-pill a:hover { color: rgba(255,255,255,0.8); }
.nav-floating-pill a.active {
  color: rgba(255,255,255,0.95);
  background: rgba(255,255,255,0.06);
}

.nav-dock {
  position: fixed;
  bottom: 12px;
  left: 50%;
  transform: translateX(-50%);
  display: flex;
  align-items: flex-end;
  gap: 4px;
  padding: 6px 10px;
  border-radius: 18px;
  background: rgba(255,255,255,0.04);
  backdrop-filter: blur(20px) saturate(150%);
  border: 0.5px solid rgba(255,255,255,0.08);
  border-top-color: rgba(255,255,255,0.15);
  box-shadow: 0 8px 32px rgba(0,0,0,0.3);
}
.nav-dock .item {
  width: 40px;
  height: 40px;
  border-radius: 10px;
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 22px;
  transition: transform 0.2s cubic-bezier(0.16, 1, 0.3, 1);
  cursor: pointer;
}
.nav-dock .item:hover { transform: scale(1.4) translateY(-8px); }
.nav-dock .item:hover + .item,
.nav-dock .item:has(+ .item:hover) { transform: scale(1.15) translateY(-3px); }

.form-cmd-search {
  display: flex;
  align-items: center;
  gap: 10px;
  padding: 10px 14px;
  border-radius: 10px;
  background: #111113;
  border: 0.5px solid #27272a;
  width: 320px;
  transition: border-color 0.15s;
}
.form-cmd-search:focus-within { border-color: #3f3f46; }
.form-cmd-search .icon { color: #52525b; font-size: 15px; flex-shrink: 0; }
.form-cmd-search input {
  flex: 1;
  background: none;
  border: none;
  outline: none;
  font-family: 'Inter', system-ui;
  font-size: 14px;
  color: #fafafa;
}
.form-cmd-search input::placeholder { color: #3f3f46; }
.form-cmd-search .shortcut {
  padding: 2px 6px;
  border-radius: 4px;
  border: 0.5px solid #27272a;
  font-family: system-ui;
  font-size: 11px;
  color: #52525b;
  flex-shrink: 0;
}

.modal-cmd-overlay {
  position: fixed;
  inset: 0;
  background: rgba(0,0,0,0.6);
  display: flex;
  justify-content: center;
  padding-top: 20vh;
  z-index: 9999;
}
.modal-cmd {
  width: min(90%, 560px);
  border-radius: 12px;
  background: #111113;
  border: 0.5px solid #27272a;
  box-shadow: 0 16px 64px rgba(0,0,0,0.5);
  overflow: hidden;
  color: #fafafa;
}
.modal-cmd .search-area {
  padding: 16px 18px;
  border-bottom: 0.5px solid #1a1a1a;
}
.modal-cmd .search-area input {
  width: 100%;
  background: none;
  border: none;
  outline: none;
  font-family: 'Inter', system-ui;
  font-size: 16px;
  color: #fafafa;
}
.modal-cmd .search-area input::placeholder { color: #3f3f46; }
.modal-cmd .results { padding: 6px; max-height: 320px; overflow-y: auto; }
.modal-cmd .result {
  display: flex;
  align-items: center;
  gap: 12px;
  padding: 10px 12px;
  border-radius: 6px;
  font-size: 14px;
  color: #d4d4d8;
  cursor: pointer;
  transition: background 0.1s;
}
.modal-cmd .result:hover, .modal-cmd .result.selected { background: rgba(255,255,255,0.04); color: #fafafa; }
.modal-cmd .result .shortcut { margin-left: auto; font-size: 11px; color: #52525b; font-family: system-ui; }
